import React from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useApp } from '../context/AppContext';

const Navbar = () => {
  const { user, cartCount, logout } = useApp();
  const navigate = useNavigate();

  const handleLogout = () => {
    logout();
    navigate('/');
  };

  return (
    <nav className="navbar glass">
      <div className="container">
        <Link to="/" className="logo">ShopSRY</Link>
        <div className="nav-links">
          <Link to="/">Bosh sahifa</Link>
          <Link to="/products">Mahsulotlar</Link>
          {user && <Link to="/orders">Buyurtmalarim</Link>}
          <Link to="/cart" className="cart-btn">
            <img src="https://img.icons8.com/ios/100/2c3e50/shopping-bag.png" alt="Cart" />
            {cartCount > 0 && <span className="cart-badge">{cartCount}</span>}
          </Link>
          {user ? (
            <span style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
              {user.role === 'admin' && <Link to="/admin" style={{ fontWeight: 600, color: '#0071e3' }}>Admin</Link>}
              <button onClick={handleLogout} style={{ background: 'none', border: 'none', cursor: 'pointer', fontSize: '14px', fontWeight: 500 }}>Chiqish</button>
            </span>
          ) : (
            <Link to="/login">Kirish</Link>
          )}
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
